local zalk = {}
local function addCheck(func) table.insert(zalk, func) end

addCheck(function() return game:GetService('ReflectionService') end)
addCheck(function() local v = Vector3.new(1,2,3)
local v2 = Vector3.new(4,5,6)
local dot = v:Dot(v2)
if dot ~= 32 then return false end
local cross = v:Cross(v2)
if cross.X ~= -3 or cross.Y ~= 6 or cross.Z ~= -3 then return false end
local sum = v + v2
if sum.X ~= 5 or sum.Y ~= 7 or sum.Z ~= 9 then return false end
local mag = v.Magnitude
if math.abs(mag - math.sqrt(14)) > 0.001 then return false end
return true
 end)
addCheck(function() local c = Color3.new(0.5,0.6,0.7)
local c2 = Color3.fromRGB(255,0,0)
if c2.R ~= 1 or c2.G ~= 0 or c2.B ~= 0 then return false end
if c.R ~= 0.5 then return false end
return true
 end)
addCheck(function() local cf = CFrame.new(1,2,3)
if cf.Position.X ~= 1 or cf.Position.Y ~= 2 or cf.Position.Z ~= 3 then return false end
local inv = cf:Inverse()
if not inv then return false end
return true
 end)
addCheck(function() local u2 = UDim2.new(0.5,10,0.3,5)
if u2.X.Scale ~= 0.5 or u2.X.Offset ~= 10 then return false end
return true
 end)
addCheck(function() local ray = Ray.new(Vector3.new(0,0,0), Vector3.new(1,0,0))
