return true
 end)
addCheck(function() local p = Instance.new('Part')
p.Name = 'Test'
if p.Name ~= 'Test' then return false end
local child = Instance.new('Part')
child.Name = 'Child'
child.Parent = p
if p:FindFirstChild('Child') ~= child then return false end
local clone = p:Clone()
if clone.Name ~= 'Test' then return false end
clone:Destroy()
p:Destroy()
return true
 end)
