for _, prop in ipairs(props) do
    local val = inst[prop.Name]
    -- If it's a writable property, try to set it
    local ok, err = pcall(function() inst[prop.Name] = val end)
    if not ok then
        -- If it fails, it might be read-only, but we still pass
    end
    break
end
