-- Just check that we can get ClassName and it matches
if inst.ClassName ~= 'File' then return false end
-- Try to get a property that exists (if any)
local props = ReflectionService:GetPropertiesOfClass('File', { Security = SecurityCapabilities.fromCurrent() })
for _, prop in ipairs(props) do
    local val = inst[prop.Name]
    -- If it's a writable property, try to set it
    local ok, err = pcall(function() inst[prop.Name] = val end)
    if not ok then
        -- If it fails, it might be read-only, but we still pass
    end
    break
end
-- Try to call a method (if any) with dummy args
local methods = ReflectionService:GetMethodsOfClass('File', { Security = SecurityCapabilities.fromCurrent() })
for _, method in ipairs(methods) do
    if method.Name ~= 'Destroy' and method.Name ~= 'Clone' and method.Name ~= 'GetChildren' then
        -- Try calling with no args (or dummy)
        local ok, err = pcall(function() inst[method.Name](inst) end)
        -- If it fails, that's fine as long as it didn't crash
    end
    break
end
inst:Destroy()
return true
 end)
