if not enumObj then return false end
local item = enumObj.Global
if not item then return false end
if item.Value == nil then return false end
if tostring(item) ~= 'Enum.ZIndexBehavior.Global' then return false end
return true
 end)
addCheck(function() local enumObj = Enum.ZIndexBehavior
if not enumObj then return false end
local item = enumObj.Sibling
if not item then return false end
if item.Value == nil then return false end
if tostring(item) ~= 'Enum.ZIndexBehavior.Sibling' then return false end
return true
 end)
local passed = 0
local failed = 0
for i, func in ipairs(zalk) do
    local ok, result = pcall(func)
    if ok and result then
        passed = passed + 1
    else
        failed = failed + 1
    end
end
local total = passed + failed
local percent = (passed / total) * 100
print('pass to fail ratio bleh: ' .. string.format('%.2f%%', percent))
print('failed dis many --> ' .. tostring(failed))
print('passed dis many --> ' .. tostring(passed))
